using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N; 
    cin>>N;

    vector<long long>a(N),ans(N);

    for(int i=0;i<N;i++) cin>>a[i];

    long long pref=1;
    for(int i=0;i<N;i++){
        ans[i]=pref;
        pref*=a[i];
    }

    long long suff=1;
    for(int i=N-1;i>=0;i--){
        ans[i]*=suff;
        suff*=a[i];
    }

    for(int i=0;i<N;i++){
        if(i) cout<<" ";
        cout<<ans[i];
    }
}

